file_path = "c:\\Users\\User\\Desktop\\kirovbelmash-next\\src\\components\\equipment\\equipmentData.ts"
with open(file_path, "r", encoding="utf-8") as f:
    text = f.read()

def replace_item(match):
    id_val = int(match.group(2))
    if id_val in updates:
        upd = updates[id_val]
        slug = f"slug: '{upd['slug']}',\n"
        seoTitle = f"    seoTitle: '{upd['seoTitle']}',\n"
        
        # We want to replace the whole id: ..., name: ..., category: ..., description: ... lines
        # But we need to keep the indentation
        return f"{match.group(1)}id: {id_val},\n{match.group(1)}{slug}{match.group(1)}{seoTitle}{match.group(1)}name: '{match.group(3)}',\n{match.group(1)}category: '{match.group(4)}',\n{match.group(1)}description:\n{match.group(1)}  '{upd['desc']}',"
    
    return match.group(0)

# Regex to match the block starting with id: ... and ending with description: '...'
pattern = re.compile(r"(\s+)id:\s*(\d+),\s+name:\s*'([^']+)',\s+category:\s*'([^']+)',\s+description:\s*'([^']+)',")
new_text = pattern.sub(replace_item, text)

# Also update the EquipmentItem interface
interface_pattern = re.compile(r"export interface EquipmentItem {(\s+)id:\s*number;")
new_text = interface_pattern.sub(r"export interface EquipmentItem {\1id: number;\1slug: string;\1seoTitle: string;", new_text)

with open(file_path, "w", encoding="utf-8") as f:
    f.write(new_text)

print("Updates completed")
